// src/pages/admin/AdminDashboard.js
import React, { useState } from "react";
import {
  Box,
  Grid,
  Paper,
  Typography,
  IconButton,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
} from "@mui/material";
import PeopleIcon from "@mui/icons-material/People";
import PersonIcon from "@mui/icons-material/Person";
import VerifiedUserIcon from "@mui/icons-material/VerifiedUser";
import PendingActionsIcon from "@mui/icons-material/PendingActions";
import DirectionsCarIcon from "@mui/icons-material/DirectionsCar";

export default function AdminDashboard() {
  const [selected, setSelected] = useState("overview");

  // Static overview numbers
  const overview = {
    users: 10,
    riders: 5,
    approvedCaptains: 4,
    pendingCaptains: 1,
    rides: 7,
  };

  // Dummy static data
  const usersData = [
    { name: "John Doe", email: "john@example.com", mobile: "1234567890" },
    { name: "Jane Smith", email: "jane@example.com", mobile: "9876543210" },
  ];
  const ridersData = [
    { name: "Rider One", email: "rider1@example.com" },
    { name: "Rider Two", email: "rider2@example.com" },
  ];
  const approvedCaptainsData = [
    { name: "Captain A", mobile: "1112223333" },
    { name: "Captain B", mobile: "4445556666" },
  ];
  const pendingCaptainsData = [
    { name: "Captain C", mobile: "7778889999" },
  ];
  const ridesData = [
    { rider: "Rider One", captain: "Captain A", pickup: "Loc1", drop: "Loc2", fare: 100, status: "Completed" },
    { rider: "Rider Two", captain: "Captain B", pickup: "Loc3", drop: "Loc4", fare: 200, status: "Pending" },
  ];

  // Cards configuration
  const cards = [
    { label: "Users", value: overview.users, icon: <PeopleIcon fontSize="large" />, key: "users" },
    { label: "Riders", value: overview.riders, icon: <PersonIcon fontSize="large" />, key: "riders" },
    { label: "Approved Captains", value: overview.approvedCaptains, icon: <VerifiedUserIcon fontSize="large" />, key: "approvedCaptains" },
    { label: "Pending Captains", value: overview.pendingCaptains, icon: <PendingActionsIcon fontSize="large" />, key: "pendingCaptains" },
    { label: "Rides", value: overview.rides, icon: <DirectionsCarIcon fontSize="large" />, key: "rides" },
  ];

  // Render table based on selected card
  const renderTable = () => {
    switch (selected) {
      case "users":
        return (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Mobile</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {usersData.map((u, idx) => (
                <TableRow key={idx}>
                  <TableCell>{u.name}</TableCell>
                  <TableCell>{u.email}</TableCell>
                  <TableCell>{u.mobile}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        );
      case "riders":
        return (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {ridersData.map((r, idx) => (
                <TableRow key={idx}>
                  <TableCell>{r.name}</TableCell>
                  <TableCell>{r.email}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        );
      case "approvedCaptains":
        return (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Mobile</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {approvedCaptainsData.map((c, idx) => (
                <TableRow key={idx}>
                  <TableCell>{c.name}</TableCell>
                  <TableCell>{c.mobile}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        );
      case "pendingCaptains":
        return (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Mobile</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {pendingCaptainsData.map((c, idx) => (
                <TableRow key={idx}>
                  <TableCell>{c.name}</TableCell>
                  <TableCell>{c.mobile}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        );
      case "rides":
        return (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Rider</TableCell>
                <TableCell>Captain</TableCell>
                <TableCell>Pickup</TableCell>
                <TableCell>Drop</TableCell>
                <TableCell>Fare</TableCell>
                <TableCell>Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {ridesData.map((r, idx) => (
                <TableRow key={idx}>
                  <TableCell>{r.rider}</TableCell>
                  <TableCell>{r.captain}</TableCell>
                  <TableCell>{r.pickup}</TableCell>
                  <TableCell>{r.drop}</TableCell>
                  <TableCell>{r.fare}</TableCell>
                  <TableCell>{r.status}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        );
      default:
        return <Typography>Select a card to see details</Typography>;
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom>
        Rider App - Admin Dashboard
      </Typography>

      <Grid container spacing={2} sx={{ mb: 3 }}>
        {cards.map((card) => (
          <Grid item xs={12} sm={6} md={2.4} key={card.label}>
            <Paper
              onClick={() => setSelected(card.key)}
              sx={{
                p: 3,
                textAlign: "center",
                boxShadow: 3,
                borderRadius: 2,
                backgroundColor: selected === card.key ? "#e0f7fa" : "#f5f5f5",
                cursor: "pointer",
                transition: "transform 0.2s",
                "&:hover": { transform: "scale(1.05)" },
              }}
            >
              <IconButton size="large" sx={{ color: "#00796b" }}>
                {card.icon}
              </IconButton>
              <Typography variant="subtitle1">{card.label}</Typography>
              <Typography variant="h5" fontWeight="bold">
                {card.value}
              </Typography>
            </Paper>
          </Grid>
        ))}
      </Grid>

      <Paper sx={{ p: 2 }}>
        {renderTable()}
      </Paper>
    </Box>
  );
}
